INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (10, 7, 1, 3001, 11300101, "vo_minigame_1012_result_1000", 8, 1, "フフ、全問正解よ！\nちゃんと勉強してるみたいで\n感心だわ♪", 10, 1, 4, 3.18);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (10, 8, 1, 3001, 11300102, "vo_minigame_1012_result_1001", 7, 1, "すごいじゃない…全問正解よ！\nま、当然といや当然よね～\nだってあたしが\n教えてやってんだから♪", 10, 1, 10, 3.33);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (10, 8, 1, 3001, 11300103, "vo_minigame_1012_result_1002", 1, 1, "全問正解！　パチパチパチ～♪\nこの難易度はもう完璧じゃない？\n次はもっと難しい問題に挑戦よ！\nあんたならできるって！", 10, 1, 10, 5.41);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (10, 5, 2, 3001, 11300104, "vo_minigame_1012_result_1003", 8, 1, "へえ…難しい問題を選んだのに\n全問正解できてるじゃない！！\nちょっとあんたすごすぎだわ…！\nパーフェクトよパーフェクト！", 10, 1, 10, 8.11);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (10, 10, 2, 3001, 11300105, "vo_minigame_1012_result_1004", 5, 1, "まる…まる…全部まる！\n難しい問題なのに全問正解よ…！\n驚いた…あんたいつの間に、\nこんなに勉強してたのよ！", 10, 1, 0, 1.31);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (10, 9, 2, 3001, 11300106, "vo_minigame_1012_result_1005", 8, 1, "ここまで完璧に正解されちゃうと\nちょっと悔しいわね…！\nけど素直に褒めてやるわ！\nえらい、えらい、えら～い！", 10, 1, 0, 4.93);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (10, 5, 3, 3001, 11300107, "vo_minigame_1012_result_1006", 8, 1, "すごい…あんたパーフェクトよ！\nこのままいけば次の試験、\n学年一位も夢じゃないかもね！\n楽しみだわ～♪", 10, 1, 4, 2.99);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (10, 8, 3, 3001, 11300108, "vo_minigame_1012_result_1007", 7, 1, "満点よ！　フフ、もうあんたに\n教えることはなにもないわ…！\n逆にあたしがあんたに教わりたい\nくらいよ！　…ね、先生♪", 10, 1, 4, 8.37);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (10, 7, 3, 3001, 11300109, "vo_minigame_1012_result_1008", 5, 1, "全・問・正・解！\n超難問揃いなのにすごいわね…！\nもしかしてだけど、\nあんたって天才！？", 10, 1, 8, 5.32);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (9, 7, 1, 3001, 11300110, "vo_minigame_1012_result_1009", 1, 1, "お、かなりいい点数ね～！\nあたしも教えがいがあるわ♪\nさ、まだまだ勉強するわよ！", 7, 1, 4, 4.77);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (9, 8, 1, 3001, 11300111, "vo_minigame_1012_result_1010", 7, 1, "うん、いい感じで点取れてるわ！\nこの調子で次は、\n満点を見せてほしいわね！", 7, 1, 4, 2.97);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (9, 5, 1, 3001, 11300112, "vo_minigame_1012_result_1011", 1, 1, "あ～惜しい！\nもうちょっとで満点じゃない！\n次はパーフェクトいけるわ！\n頑張りましょ！", 7, 1, 0, 3.47);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (9, 8, 2, 3001, 11300113, "vo_minigame_1012_result_1012", 7, 1, "すごい、かなりできてるわよ！\n難しい問題なのにやるじゃない！\nあとは目指せ、満点ね！", 7, 1, 4, 5.32);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (9, 8, 2, 3001, 11300114, "vo_minigame_1012_result_1013", 7, 1, "うん、かなりいい感じよ！\nあんたには赤点の心配なんて\nまーったくなさそうね♪\nでも勉強はやめさせないけど！", 7, 1, 10, 6.49);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (9, 5, 2, 3001, 11300115, "vo_minigame_1012_result_1014", 1, 1, "あーあとちょっとで\n全問正解だったのに！\n難しい問題だけどあんたなら\n次は満点狙えるわ！", 7, 1, 0, 3.56);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (9, 8, 3, 3001, 11300116, "vo_minigame_1012_result_1015", 1, 1, "うん、ほとんど正解よ！\nこんな難しい問題なのに、\nすごいじゃない！\nやっぱりあんた只者じゃないわ！", 7, 1, 10, 5.67);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (9, 7, 3, 3001, 11300117, "vo_minigame_1012_result_1016", 1, 1, "着実に成長してるって感じね？\nあんたならこの難問でも、\nいつか満点取れちゃうかも…！", 7, 1, 10, 2.85);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (9, 5, 3, 3001, 11300118, "vo_minigame_1012_result_1017", 1, 1, "うわー惜しいわね！\nもうちょっとで満点よ？\nま、あたしでも悩む難問だから、\nこの点数は胸を張っていいわ！", 7, 1, 0, 3.88);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (6, 3, 1, 3001, 11300119, "vo_minigame_1012_result_1018", 1, 1, "正解率は半分くらいか～\n悪くはないんだけど、あんたなら\nこんなもんじゃないでしょ？", 4, 1, 0, 4.12);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (6, 9, 1, 3001, 11300120, "vo_minigame_1012_result_1019", 1, 1, "んーはっきり言っちゃうと\n中途半端な点数ね…\nまあいいわ！こっからガンガン\n点数上げていくわよ！", 4, 1, 0, 4.34);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (6, 3, 1, 3001, 11300121, "vo_minigame_1012_result_1020", 1, 1, "う～ん、正直物足りない点数ね！\nあんたには期待してんだから、\nもっと頑張んなさい！", 4, 1, 0, 3.15);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (6, 9, 2, 3001, 11300122, "vo_minigame_1012_result_1021", 1, 1, "半分くらいの正解率か\n難しい問題だから仕方ないわね…\nでもあんたはもっとできる！\nだってあたしがついてんのよ！", 4, 1, 0, 5.3);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (6, 8, 2, 3001, 11300123, "vo_minigame_1012_result_1022", 1, 1, "うん、そこそこできんじゃない！\n頑張って勉強して\nさらに上を目指しましょ！", 4, 1, 0, 2.55);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (6, 1, 2, 3001, 11300124, "vo_minigame_1012_result_1023", 7, 1, "難問なのにこの正解率は\nよくやってる方よね！\nでもこんなところで\n満足してんじゃないわよ！？", 4, 1, 0, 4.19);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (6, 7, 3, 3001, 11300125, "vo_minigame_1012_result_1024", 1, 1, "難問なのに半分くらい正解\nできてんじゃない♪\nこの調子でもっと学力\n上げていきましょ！", 4, 1, 0, 3.43);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (6, 1, 3, 3001, 11300126, "vo_minigame_1012_result_1025", 1, 1, "よし、平均点ってとこね！\nちゃんと勉強してるみたいで\n安心したわ～♪", 4, 1, 0, 0.0);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (6, 8, 3, 3001, 11300127, "vo_minigame_1012_result_1026", 7, 1, "難問揃いでこの正解率は\n大したもんよ！\nま、もっといい点取りたいんなら\n勉強、付き合ったげるわ！", 4, 1, 0, 3.72);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (3, 3, 1, 3001, 11300128, "vo_minigame_1012_result_1027", 2, 1, "なるほど…\nこれは教えがいがあるわね\nビシバシ鍛えてやるから\n覚悟しなさい！", 1, 1, 1, 3.5);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (3, 4, 1, 3001, 11300129, "vo_minigame_1012_result_1028", 2, 1, "ちょっとあんた、\n全然できてないじゃない！\n…まさかこれが本気だなんて\n言わないわよね～？", 1, 1, 1, 3.25);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (3, 3, 1, 3001, 11300130, "vo_minigame_1012_result_1029", 2, 1, "うーん……適当に答えても\nこれくらい正解できるわよ？\nちょっと本腰入れて\n教えないとね……！", 1, 1, 0, 4.62);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (3, 9, 2, 3001, 11300131, "vo_minigame_1012_result_1030", 1, 1, "…ま、まあこの問題は\nあんたには難しすぎたのかもね\nちょっとずつでいいから、\nレベルアップしていきましょ！", 1, 1, 0, 4.5);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (3, 3, 2, 3001, 11300132, "vo_minigame_1012_result_1031", 3, 1, "んー結構ミスっちゃってるわね…\nこのまま続けるのもいいけど、\n簡単な問題からやり直すのも\nありかもよ～？", 1, 1, 9, 0.01);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (3, 9, 2, 3001, 11300133, "vo_minigame_1012_result_1032", 9, 1, "あらら、あんたにはちょっと\n難しすぎたかしら…？\nもう一回やり直しましょうか！", 1, 1, 9, 0.01);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (3, 3, 3, 3001, 11300134, "vo_minigame_1012_result_1033", 3, 1, "うーん、残念な結果ね…\n超難問だから仕方ないけど\n無理せず簡単な問題から挑戦\nしてもいいかもよ？", 1, 1, 6, 0.01);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (3, 3, 3, 3001, 11300135, "vo_minigame_1012_result_1034", 9, 1, "正解率はかなり悪いわね…\nまあ難しい問題だもんね…！\nそのチャレンジ精神は買うわ！", 1, 1, 0, 2.97);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (3, 3, 3, 3001, 11300136, "vo_minigame_1012_result_1035", 1, 1, "なんとか０点は免れたわね…\n難問揃いだけど、\nもっと頑張っていきましょ！", 1, 1, 0, 3.1);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (0, 6, 1, 3001, 11300137, "vo_minigame_1012_result_1036", 2, 1, "…あんたさ、０点なんて\n逆に取るの難しいわよ！？\nまさか狙ったわけじゃ\nないでしょーね～！？", 0, 1, 1, 4.31);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (0, 2, 1, 3001, 11300138, "vo_minigame_1012_result_1037", 2, 1, "０点って…\nあんたふざけてんの！？\nちゃんとやらないなら\n電撃魔法くらわせるわよ！？", 0, 1, 1, 0.1);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (0, 9, 1, 3001, 11300139, "vo_minigame_1012_result_1038", 3, 1, "もしかしたらあんたは\n勉強向いてないのかもね…\n…勉強だけがすべてじゃないわ\n違うとこで頑張りましょ！", 0, 1, 9, 4.23);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (0, 3, 2, 3001, 11300140, "vo_minigame_1012_result_1039", 2, 1, "怒んないから正直に言って？\n…ふざけて答えたでしょ？\nほら、正直に\n言・い・な・さ・い？", 0, 1, 0, 4.38);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (0, 8, 2, 3001, 11300141, "vo_minigame_1012_result_1040", 2, 1, "あんたの点数は～～…\n…はい！　０てーん！！\n…って、ふざけんなーー！！！", 0, 1, 0, 3.58);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (0, 4, 2, 3001, 11300142, "vo_minigame_1012_result_1041", 2, 1, "０点ってどういうこと！？\nいやあんた、逆にすごいわよ！？\n目つぶってやったとしても\n１点は取れるから！", 0, 1, 1, 2.02);
