INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (-1, 7, 1, 3001, 12300101, "vo_minigame_1012_result_1045", 1, 2, "はい、よくできました！\n基礎はもう完璧ね！\n次はもっと難しい問題にも\nチャレンジしちゃいなさいよ！", 20, 1, 10, 3.74);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (-1, 1, 1, 3001, 12300102, "vo_minigame_1012_result_1046", 9, 2, "なによあんた、走り出したペンが\n止まらないって感じ？\nったくシンプルにすごいじゃない\n花丸あげるわ！", 20, 1, 0, 3.85);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (-1, 5, 1, 3001, 12300103, "vo_minigame_1012_result_1047", 5, 2, "すごい点数ね…！\nあんた勉強してないとか言って\nホントはめちゃくちゃやってる\nパターンのやつね！？", 20, 1, 8, 0.01);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (-1, 8, 2, 3001, 12300104, "vo_minigame_1012_result_1048", 7, 2, "勉強の成果、\nちゃんとでてんじゃない！\nあたしもあんたの先生として、\n鼻が高いわ～♪", 20, 1, 4, 2.86);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (-1, 5, 2, 3001, 12300105, "vo_minigame_1012_result_1049", 3, 2, "オッケー！　もう十分よ！\nこれ以上でき過ぎちゃったら、\nあたしが教える必要なくなるわ！", 20, 1, 9, 2.02);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (-1, 5, 2, 3001, 12300106, "vo_minigame_1012_result_1050", 1, 2, "難しい問題を選んだつもりなのに\nすごい正解数ね…！\nでもまだ上がある…\n次は最難関に挑戦よ！", 20, 1, 0, 4.46);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (-1, 5, 3, 3001, 12300107, "vo_minigame_1012_result_1051", 4, 2, "すごいすごいとは思ってたけど、\nあんた勉強も完璧なの…？\nそりゃみんなあんたに惚れ…\nや、な、なんでもない！！", 20, 1, 7, 6.85);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (-1, 5, 3, 3001, 12300108, "vo_minigame_1012_result_1052", 9, 2, "この問題、あたしでも悩む\n超難問なのに…\nふふっ、もう褒めるしかないわ！\n大変よくできました！", 20, 1, 0, 3.79);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (-1, 4, 3, 3001, 12300109, "vo_minigame_1012_result_1053", 4, 2, "別に顔赤くなんてなってない！\n頭がいい人が好きとか…\nかっこいいとか…\n…思ってないからね！", 20, 1, 7, 0.01);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (-1, 5, 1, 3001, 12300110, "vo_minigame_1012_result_1054", 5, 2, "スピードも正確さも完璧…\n文句なしの満点だわ！\nあんた将来、とんでもない人に\nなっちゃうんじゃない！？", 20, 1, 0, 0.0);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (-1, 5, 2, 3001, 12300112, "vo_minigame_1012_result_1054", 5, 2, "スピードも正確さも完璧…\n文句なしの満点だわ！\nあんた将来、とんでもない人に\nなっちゃうんじゃない！？", 20, 1, 0, 0.0);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (-1, 5, 3, 3001, 12300114, "vo_minigame_1012_result_1054", 5, 2, "スピードも正確さも完璧…\n文句なしの満点だわ！\nあんた将来、とんでもない人に\nなっちゃうんじゃない！？", 20, 1, 0, 0.0);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (19, 5, 1, 3001, 12300116, "vo_minigame_1012_result_1056", 7, 2, "おお～かなり正解できてるわね！\nこの調子でもっとすごい点\n目指しちゃうわよ！", 15, 1, 10, 3.0);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (19, 8, 1, 3001, 12300117, "vo_minigame_1012_result_1057", 8, 2, "うん、バッチリいい感じよ！\nちゃんと勉強してるみたいで\n関心関心♪", 15, 1, 10, 0.01);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (19, 5, 1, 3001, 12300118, "vo_minigame_1012_result_1058", 8, 2, "え、こんなにいい点取れたのに\nまだ満足してないの？\nなによその向上心…\nいいじゃない！", 15, 1, 0, 4.01);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (19, 8, 2, 3001, 12300119, "vo_minigame_1012_result_1059", 7, 2, "スピードも正解数もいい感じよ！\nねえねえ、この調子で\nてっぺん目指しちゃう？", 15, 1, 10, 2.83);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (19, 10, 2, 3001, 12300120, "vo_minigame_1012_result_1060", 10, 2, "この難易度でも\nスラスラ答えちゃうなんて…\nあんたって\nほんとすごいやつよね…！", 15, 1, 0, 0.0);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (19, 8, 2, 3001, 12300121, "vo_minigame_1012_result_1061", 7, 2, "これだけ正解できたら\n勉強も楽しいわよね♪\nさ、まだまだ続けるわよ～！", 15, 1, 4, 3.66);
