INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (19, 8, 3, 3001, 12300123, "vo_minigame_1012_result_1063", 1, 2, "すごい！　とってもいい成績よ！\nこの難問も、あんたにかかりゃ\nイチコロってやつ？", 15, 1, 0, 2.7);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (19, 5, 3, 3001, 12300124, "vo_minigame_1012_result_1064", 9, 2, "あんた…もしかして\nあたしより点数いいかも？\nあ、あたしもあんたを見習って\n勉強しないとね…！", 15, 1, 9, 3.98);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (14, 7, 1, 3001, 12300131, "vo_minigame_1012_result_1067", 1, 2, "うん、なかなかいい点数よ！\nでもまだまだ頑張れるわよね？\nはい、次いきましょ！", 10, 1, 0, 2.51);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (14, 1, 1, 3001, 12300132, "vo_minigame_1012_result_1068", 7, 2, "十分優秀な成績だけど\nあんたならもっとできる！\nさ、頑張って勉強するわよ！", 10, 1, 0, 4.16);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (14, 8, 1, 3001, 12300133, "vo_minigame_1012_result_1069", 7, 2, "うん、いい感じね！\nこの調子で少しずつ、\n正解数を増やしてくわよ！", 10, 1, 0, 2.07);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (14, 8, 2, 3001, 12300134, "vo_minigame_1012_result_1070", 1, 2, "難問揃いなのに、\nけっこーいい感じじゃない！\nちゃんとできてるから\n自信もっていいわよ！", 10, 1, 0, 3.51);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (14, 1, 2, 3001, 12300135, "vo_minigame_1012_result_1071", 1, 2, "難しい問題でも基礎は大事よ！\nこの調子でどんどん\n点数上げていきましょう！", 10, 1, 0, 0.0);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (14, 1, 2, 3001, 12300136, "vo_minigame_1012_result_1072", 7, 2, "10問以上取れてるわね！\nえ、まだ物足りない？\nフフ、じゃあもっと上\n目指しちゃう？", 10, 1, 0, 4.3);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (14, 8, 3, 3001, 12300137, "vo_minigame_1012_result_1073", 7, 2, "うん、この難問でこの点数は\n十分すぎる出来よね！\nま、あんたならもっといい点\n目指しちゃうんだろうけど♪", 10, 1, 0, 4.47);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (14, 8, 3, 3001, 12300138, "vo_minigame_1012_result_1074", 9, 2, "はいお疲れ～\nなかなか良い点数じゃない\n…あたしも勉強しないとね！", 10, 1, 0, 3.68);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (14, 5, 3, 3001, 12300139, "vo_minigame_1012_result_1075", 1, 2, "おお～10問以上\n正解してんじゃない！\nあんたやっぱり\nただ者じゃないわね～", 10, 1, 0, 3.34);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (14, 1, 1, 3001, 12300141, "vo_minigame_1012_result_1077", 8, 2, "うん正解率は申し分なしね！\nあとはもっと早く解ければ\nもっと点数は伸びてくわよ！\nこの調子で頑張っていきましょ！", 10, 1, 0, 6.58);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (14, 1, 2, 3001, 12300143, "vo_minigame_1012_result_1077", 8, 2, "うん正解率は申し分なしね！\nあとはもっと早く解ければ\nもっと点数は伸びてくわよ！\nこの調子で頑張っていきましょ！", 10, 1, 0, 6.58);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (14, 1, 3, 3001, 12300145, "vo_minigame_1012_result_1077", 8, 2, "うん正解率は申し分なしね！\nあとはもっと早く解ければ\nもっと点数は伸びてくわよ！\nこの調子で頑張っていきましょ！", 10, 1, 0, 6.58);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (9, 1, 1, 3001, 12300146, "vo_minigame_1012_result_1078", 7, 2, "ふ～ん、まあまあの出来だわ\n悪くはないんだけど…あんたには\nもっともっと期待してるわ～", 5, 1, 0, 4.24);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (9, 7, 1, 3001, 12300147, "vo_minigame_1012_result_1079", 1, 2, "うん、頑張ったけど…\n正直もっと正解できるかもね～？\nこんなのあんたには通過点！\nさらに良い点目指してみない？", 5, 1, 0, 4.74);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (9, 1, 1, 3001, 12300148, "vo_minigame_1012_result_1080", 1, 2, "まあまあな点数だけど、\n自分的に手ごたえはどう？\nダメだって思ってんなら、\nまだまだ伸びる余地ありね！", 5, 1, 0, 0.0);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (9, 8, 2, 3001, 12300149, "vo_minigame_1012_result_1081", 1, 2, "うん、中々の出来ね！\nでもあんたはもっといい点\n取れるはずよ！\nもっと頑張りましょうか！", 5, 1, 0, 2.21);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (9, 3, 2, 3001, 12300150, "vo_minigame_1012_result_1082", 1, 2, "ん～はっきり言って微妙ね！\nま、難しい問題だし、\n勉強すれば\n点数は上がっていくと思うわ！", 5, 1, 0, 2.46);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (9, 3, 2, 3001, 12300151, "vo_minigame_1012_result_1083", 1, 2, "ん～…\n10点には届かなかったか～\n次は10点越え目指して\n頑張ってみない？", 5, 1, 0, 2.94);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (9, 7, 3, 3001, 12300152, "vo_minigame_1012_result_1084", 1, 2, "はいお疲れ～\n点数的にはまあまあってとこね！\nま、超難問だし頑張ったわよ", 5, 1, 0, 4.19);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (9, 1, 3, 3001, 12300153, "vo_minigame_1012_result_1085", 1, 2, "うん、かなり難しい問題なのに\n最後までやり遂げたわね\n次はもっといい点目指してみる？", 5, 1, 0, 0.0);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (9, 3, 3, 3001, 12300154, "vo_minigame_1012_result_1086", 1, 2, "ちょっとミスが多かったかもね～\nでも間違えた所は復習して\n次は正解するわよー！", 5, 1, 0, 2.63);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (4, 3, 1, 3001, 12300155, "vo_minigame_1012_result_1087", 1, 2, "あら…あんまり良くない点数ね～\nどうしたの、調子でも悪かった？\n次はもっと頑張りましょうか", 1, 1, 0, 5.53);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (4, 3, 1, 3001, 12300156, "vo_minigame_1012_result_1088", 3, 2, "ん～…正解数は\n物足りないわね～\nもうちょっと勉強の時間\n増やしちゃおっか？", 1, 1, 9, 0.01);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (4, 3, 1, 3001, 12300157, "vo_minigame_1012_result_1089", 1, 2, "ん～…あんたならもうちょと\nいい点取れんでしょ～？\nもっと頑張んなさいよ\n期待してやってんだからさ！", 1, 1, 3, 4.15);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (4, 9, 2, 3001, 12300158, "vo_minigame_1012_result_1090", 9, 2, "ん～今のあんたには、\nこの問題は難しかったかしら…\n難易度下げてチャレンジするのも\nありかもね～？", 1, 1, 9, 0.01);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (4, 3, 2, 3001, 12300159, "vo_minigame_1012_result_1091", 1, 2, "あんまり出来は良くないわね～\n難しい問題だししょうがないけど\n次はもっと頑張ってほしいわ！", 1, 1, 0, 5.37);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (4, 3, 2, 3001, 12300160, "vo_minigame_1012_result_1092", 1, 2, "なるほど…\nちょっと苦手な問題が多かった？\nもう一度チャレンジ\nしてみましょうか～", 1, 1, 0, 1.44);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (4, 3, 3, 3001, 12300161, "vo_minigame_1012_result_1093", 3, 2, "んん～…問題が難しすぎた？\n無理に難しい問題続けるより、\n難易度下げた方が\n勉強の効率良いかもよ～？", 1, 1, 0, 0.0);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (4, 3, 3, 3001, 12300162, "vo_minigame_1012_result_1094", 9, 2, "…あんまり点数取れなかったわね\nこれはあたしにも難しい問題だし\nそう落ち込まなくても大丈夫！\n次頑張りましょ！", 1, 1, 3, 2.91);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (4, 5, 3, 3001, 12300163, "vo_minigame_1012_result_1095", 1, 2, "ごめん、ちょっと難しすぎた？\nもう一度チャレンジするも良し、\n難易度を下げるも良し、\nあんたがやる気なら付き合うわ！", 1, 1, 0, 2.61);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (0, 4, 1, 3001, 12300164, "vo_minigame_1012_result_1096", 2, 2, "ちょっとあんた…\nやる気ないわよね～！？\n次こんな点数取ったら\n怒るわよ！", 0, 1, 1, 3.63);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (0, 6, 1, 3001, 12300165, "vo_minigame_1012_result_1097", 2, 2, "はあ…自分で何点取ったか\n分かってるわよね～…？\n０点よ０点！　舐めてんの！？", 0, 1, 1, 4.16);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (0, 3, 1, 3001, 12300166, "vo_minigame_1012_result_1098", 3, 2, "うう～頭痛い…\nあんたのせいよ！\nなに０点って！\nはあ、このままじゃ赤点よ～…", 0, 1, 6, 0.01);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (0, 6, 2, 3001, 12300167, "vo_minigame_1012_result_1099", 2, 2, "ねえ、あんた本気でやったの？\nまさか適当にやるわけないわよね\n…分かった、\nもう一回チャレンジするのよ！", 0, 1, 0, 5.75);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (0, 4, 2, 3001, 12300168, "vo_minigame_1012_result_1100", 2, 2, "あ…あんた、０点よ０点…！\nあたしの教え方が悪かった…？\n…燃えてきたわ！\n絶対あんたの学力上げてやる！", 0, 1, 1, 5.64);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (0, 8, 2, 3001, 12300169, "vo_minigame_1012_result_1101", 4, 2, "ちょっと待って採点ミスかも…\n…いや合ってるわね。はい０点\n…って０点！？\nふざけんなーー！", 0, 1, 8, 5.73);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (0, 5, 3, 3001, 12300170, "vo_minigame_1012_result_1102", 3, 2, "あらら…０点よ\nま、難しい問題だしね…\n…つっても０点は無いわ！\n一問くらい正解しなさいよ！", 0, 1, 1, 5.32);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (0, 3, 3, 3001, 12300171, "vo_minigame_1012_result_1103", 9, 2, "残念だけど０点よ\nま、まあ前向きにとらえるなら、\n今が底よ！　どん底！\nあとは上がってくだけね！", 0, 1, 9, 2.37);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (0, 9, 3, 3001, 12300172, "vo_minigame_1012_result_1104", 1, 2, "…かなり出来が悪いわね\n一旦休憩しましょうか？\nリフレッシュして頭切り替えて\nもう一度頑張りましょう！", 0, 1, 3, 4.25);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (0, 7, 0, 1001, 13100101, "vo_minigame_1012_gamestart_100", 7, 3, "さ、勉強を始めるわよ", 0, 1, 0, 0.0);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (0, 1, 0, 1001, 13100102, "vo_minigame_1012_gamestart_101", 1, 3, "よし、勉強の成果を見てやるわ！", 0, 1, 0, 0.0);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (0, 1, 0, 1001, 13100103, "vo_minigame_1012_gamestart_102", 7, 3, "じゃあ試験するわよ。はい教科書閉じて！", 0, 1, 0, 1.82);
