INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (-1, 3, 1, 3001, 22300102, "vo_minigame_1012_result_2046", 2, 2, "点数イケイケじゃん！　\nもしかして、ヒデサイには\n簡単過ぎた感じ？", 20, 2, 11, 2.31);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (-1, 3, 1, 3001, 22300103, "vo_minigame_1012_result_2047", 3, 2, "きゃはっ、もうバッチリだね♪\n他の問題も教えてほしーし\n次はムズいのいっちゃう？", 20, 2, 11, 0.01);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (-1, 6, 2, 3001, 22300104, "vo_minigame_1012_result_2048", 7, 2, "ムズい問題なのに\n〇でいっぱいじゃん…！\nさっすが、ヒデサイセンセー！", 20, 2, 11, 4.33);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (-1, 6, 2, 3001, 22300105, "vo_minigame_1012_result_2049", 2, 2, "一緒にベンキョー\nしてるだけなのに\nうちまで賢くなった気する…！\nマジありがとね", 20, 2, 0, 5.73);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (-1, 6, 2, 3001, 22300106, "vo_minigame_1012_result_2050", 6, 2, "これってムズい問題だよね？\nなんで簡単に解いてくの？\nヒデサイ、すごすぎ！", 20, 2, 8, 0.01);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (-1, 6, 3, 3001, 22300107, "vo_minigame_1012_result_2051", 3, 2, "おにムズなのに\n答えるの一瞬だったね…！\nヒデサイ、頭良すぎじゃん？", 20, 2, 0, 4.02);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (-1, 2, 3, 3001, 22300108, "vo_minigame_1012_result_2052", 3, 2, "まる、まる、はなまる～\nきゃははっ、すごっ！\nさっすがヒデサイ！\nハイタッチー！", 20, 2, 11, 5.24);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (-1, 2, 3, 3001, 22300109, "vo_minigame_1012_result_2053", 3, 2, "これだけ教えてもらったら\nもうテストもよゆーっしょ！\nヒデサイ、マジありがとね♪", 20, 2, 4, 4.6);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (-1, 6, 1, 3001, 22300110, "vo_minigame_1012_result_2054", 10, 2, "うちこんなの初めて見た…！\nヒデサイセンセー、神ってる！\nそだ、記念にこれ飾っとこうよ♪\nえ、それはちょっち恥ずかしい？", 20, 2, 0, 5.57);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (-1, 6, 2, 3001, 22300112, "vo_minigame_1012_result_2054", 10, 2, "うちこんなの初めて見た…！\nヒデサイセンセー、神ってる！\nそだ、記念にこれ飾っとこうよ♪\nえ、それはちょっち恥ずかしい？", 20, 2, 0, 5.57);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (-1, 6, 3, 3001, 22300114, "vo_minigame_1012_result_2054", 10, 2, "うちこんなの初めて見た…！\nヒデサイセンセー、神ってる！\nそだ、記念にこれ飾っとこうよ♪\nえ、それはちょっち恥ずかしい？", 20, 2, 0, 5.57);
