INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (19, 6, 1, 3001, 22300117, "vo_minigame_1012_result_2057", 3, 2, "おーさすがヒデサイ！\n〇の数も超ヒデサイだね♪\nイェーイ！", 15, 2, 11, 5.23);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (19, 3, 1, 3001, 22300118, "vo_minigame_1012_result_2058", 2, 2, "ヒデサイ、〇でいっぱいじゃん♪\nうちも教えてもらったとこは\nけっこー覚えてきたかも？", 15, 2, 11, 3.23);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (19, 3, 2, 3001, 22300119, "vo_minigame_1012_result_2059", 7, 2, "アゲアゲな点数じゃん！\nとりま、どやっとく？\nせーの、どやぁ…！", 15, 2, 10, 6.0);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (19, 7, 2, 3001, 22300120, "vo_minigame_1012_result_2060", 7, 2, "ムズい問題も\nだんだん解けてくると\nたのしーね\nちょっち感動～", 15, 2, 0, 0.0);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (19, 6, 2, 3001, 22300121, "vo_minigame_1012_result_2061", 6, 2, "たくさん解いても\nヒデサイは頭パンクしないの？\nスゴ…！", 15, 2, 0, 0.0);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (19, 6, 3, 3001, 22300122, "vo_minigame_1012_result_2062", 2, 2, "わわっ、〇ばっかり…！\nこの調子なら\n次は20に届くんじゃない？", 15, 2, 3, 3.06);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (19, 6, 3, 3001, 22300123, "vo_minigame_1012_result_2063", 5, 2, "15個以上〇って…！\nおにムズなのに、すごすぎ～\nうちもがんばらなきゃ！", 15, 2, 0, 5.74);
