INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (14, 3, 1, 3001, 22300131, "vo_minigame_1012_result_2067", 3, 2, "きゃはっ、いい感じ！\nたくさん解けてるし\nベンキョーの成果\n…ってやつだね♪", 10, 2, 0, 0.0);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (14, 2, 1, 3001, 22300132, "vo_minigame_1012_result_2068", 2, 2, "10個以上〇だね♪\nヒデサイのおかげで\nうちも、ちょっち\n頭よくなったかな？", 10, 2, 0, 0.0);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (14, 10, 1, 3001, 22300133, "vo_minigame_1012_result_2069", 2, 2, "けっこー解けたよね？\nやっぱ〇増えると\nバイブス上がる～", 10, 2, 0, 2.28);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (14, 2, 2, 3001, 22300134, "vo_minigame_1012_result_2070", 2, 2, "ベンキョーってあれだね\nわかった気すると\nまあまあたのしーかも！", 10, 2, 0, 0.0);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (14, 6, 2, 3001, 22300135, "vo_minigame_1012_result_2071", 2, 2, "10個以上解けてる！？\nけっこーいいペースだよね？\nいい調子、いい調子～", 10, 2, 0, 2.1);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (14, 2, 2, 3001, 22300136, "vo_minigame_1012_result_2072", 3, 2, "けっこー解けてる！\nムズい問題もヒデサイと\n一緒なら怖くないね♪", 10, 2, 0, 2.13);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (14, 7, 3, 3001, 22300137, "vo_minigame_1012_result_2073", 7, 2, "おにムズ問題でも教えるの\n超やさしーし、マジ感謝！\n一緒にがんばろーね♪", 10, 2, 0, 0.0);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (14, 6, 3, 3001, 22300138, "vo_minigame_1012_result_2074", 6, 2, "おにムズなのに\n〇けっこーあるし\nヒデサイすごくない？", 10, 2, 0, 0.0);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (14, 6, 3, 3001, 22300139, "vo_minigame_1012_result_2075", 5, 2, "おにムズでこのペースは\nすごいんじゃ…？\nうちもがんばってついてくね！", 10, 2, 0, 4.21);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (9, 0, 1, 3001, 22300146, "vo_minigame_1012_result_2078", 3, 2, "悪くないよね？\nでもでも\nヒデサイとうちなら\nもっとできる気する！", 5, 2, 0, 1.94);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (9, 4, 1, 3001, 22300147, "vo_minigame_1012_result_2079", 0, 2, "もっと〇ほしーね…\n地道にやるしか\nないっぽいし\nもっかい教えてくれる？", 5, 2, 0, 2.28);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (9, 4, 1, 3001, 22300148, "vo_minigame_1012_result_2080", 4, 2, "ベンキョーしたけど\nわかんないとこばっか…\nヒデサイセンセー、助けて～", 5, 2, 0, 0.0);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (9, 4, 2, 3001, 22300149, "vo_minigame_1012_result_2081", 3, 2, "やっぱムズかったね…\nでも次はもうちょい\nできそーな気がするよ！", 5, 2, 0, 2.67);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (9, 10, 2, 3001, 22300150, "vo_minigame_1012_result_2082", 6, 2, "問題ムズいし、この点数は\nありよりのありっしょ？\nえ、もっとできた感じ？", 5, 2, 0, 4.68);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (9, 9, 2, 3001, 22300151, "vo_minigame_1012_result_2083", 9, 2, "どこ間違ったんだろ？\nうちさっぱりだった…\nやっぱムズいだけあるね", 5, 2, 0, 0.0);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (9, 0, 3, 3001, 22300152, "vo_minigame_1012_result_2084", 3, 2, "激ムズだけど\nやることは一緒だよね？\nうちもヒデサイについてくから\nコツコツがんばろ！", 5, 2, 0, 3.55);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (9, 4, 3, 3001, 22300153, "vo_minigame_1012_result_2085", 6, 2, "やっぱおにムズだね…\nそだ、迷ったら\nヒント使うのも\nありよりのあり？", 5, 2, 0, 2.51);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (9, 9, 3, 3001, 22300154, "vo_minigame_1012_result_2086", 5, 2, "やっぱテストって\nなんとなくじゃ無理？\n覚えるしかないの？\nじゃあがんばるしかないね…", 5, 2, 0, 6.15);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (4, 4, 1, 3001, 22300155, "vo_minigame_1012_result_2087", 9, 2, "できたと思ったけど\nそーじゃなかった系？\nテストってマジきびしー…", 1, 2, 6, 4.12);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (4, 4, 1, 3001, 22300156, "vo_minigame_1012_result_2088", 4, 2, "うーん…さっぱり！\nでも簡単な問題なんだよね…？\nもっかいやってみる？", 1, 2, 6, 0.01);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (4, 0, 1, 3001, 22300157, "vo_minigame_1012_result_2089", 3, 2, "うちらまだまだ\nベンキョーちうだし…\nこれからだよねっ？\nね、ヒデサイ！", 1, 2, 0, 5.28);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (4, 0, 2, 3001, 22300158, "vo_minigame_1012_result_2090", 3, 2, "ちょっとずつ覚えれば\nおーけーっしょ！\nうちと一緒に\nベンキョーだね！", 1, 2, 0, 2.89);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (4, 0, 2, 3001, 22300159, "vo_minigame_1012_result_2091", 7, 2, "うちベンキョー苦手でも\nヒデサイとベンキョー\nするのは好き！　だから\nもっかい教えてくれる？", 1, 2, 0, 5.45);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (4, 4, 2, 3001, 22300160, "vo_minigame_1012_result_2092", 10, 2, "覚えても、すぐ忘れるんだけど\nどしたらいい？\nあ、そーゆうとき\nフクシューする感じ？", 1, 2, 3, 4.29);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (4, 4, 3, 3001, 22300161, "vo_minigame_1012_result_2093", 8, 2, "ムズ過ぎ！\n頭パンクするかと思った…！\nヒデサイ、うちの頭\nふぅふぅして～", 1, 2, 6, 4.64);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (4, 9, 3, 3001, 22300162, "vo_minigame_1012_result_2094", 5, 2, "おにムズ過ぎてテンサゲ～\nでもヒデサイがんばってるし\nうちもがんばる！", 1, 2, 0, 3.14);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (4, 7, 3, 3001, 22300163, "vo_minigame_1012_result_2095", 4, 2, "ヒデサイと同じ点数で\nちょっち安心したかも\n一緒にがんばろーね！\n置いてっちゃやだよ？", 1, 2, 0, 6.59);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (0, 3, 1, 3001, 22300164, "vo_minigame_1012_result_2096", 3, 2, "…まあ、これより下はないし\n次は大逆転\n点数爆上がりっしょ！", 0, 2, 0, 0.0);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (0, 9, 1, 3001, 22300165, "vo_minigame_1012_result_2097", 10, 2, "０点じゃん…\nそだ、次はえんぴつ転がして\n選ぶ作戦やってみる？", 0, 2, 5, 2.2);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (0, 4, 1, 3001, 22300166, "vo_minigame_1012_result_2098", 4, 2, "考えるの無理な時あるよね…\nヒデサイもそーゆう\n感じだったの？", 0, 2, 6, 0.01);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (0, 6, 2, 3001, 22300167, "vo_minigame_1012_result_2099", 2, 2, "え、ヒデサイも０点？\nじゃあうちと一緒じゃん♪\nまあ焦んないで\nベンキョーしてこーよ！", 0, 2, 3, 2.8);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (0, 9, 2, 3001, 22300168, "vo_minigame_1012_result_2100", 4, 2, "むむむ～…０点…！\n覚えてもすぐ忘れちゃうし\nベンキョーってマジ大変", 0, 2, 6, 3.22);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (0, 4, 2, 3001, 22300169, "vo_minigame_1012_result_2101", 0, 2, "０点だね…\nでも、へーきへーき\nリベンジしたら、結果オーライ！", 0, 2, 11, 2.1);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (0, 0, 3, 3001, 22300170, "vo_minigame_1012_result_2102", 2, 2, "おやつ休憩して\nリベンジしよっ！\n甘いの食べたら、イケるっしょ！", 0, 2, 3, 2.74);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (0, 6, 3, 3001, 22300171, "vo_minigame_1012_result_2103", 9, 2, "ヒデサイでも\nおにムズな感じ？\nじゃあ、このテスト\n誰も解けなくない？", 0, 2, 9, 3.0);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (0, 10, 3, 3001, 22300172, "vo_minigame_1012_result_2104", 2, 2, "…あれ？\n０が〇に見えてきた！\nきゃはっ、ちょっち\nやる気出てきたかも！", 0, 2, 0, 4.37);
